import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../components/AuthContext';

const HomePage = () => {
  const [cars, setCars] = useState([]);
  const [allCars, setAllCars] = useState([]);
  const [brands, setBrands] = useState([]);
  const [selectedCar, setSelectedCar] = useState(null);
  const [loading, setLoading] = useState(true);
  const [searchKeyword, setSearchKeyword] = useState('');
  const [searchResults, setSearchResults] = useState(null);
  const [selectedBrand, setSelectedBrand] = useState(null);
  const navigate = useNavigate();
  const { user } = useAuth();

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    if (selectedBrand) {
      const filtered = allCars.filter(car => car.brand === selectedBrand);
      setCars(filtered);
      setSearchResults(null);
    } else {
      setCars(allCars.slice(0, 6));
    }
  }, [selectedBrand, allCars]);

  const fetchData = async () => {
    try {
      const carsRes = await axios.get('http://localhost:5000/api/cars');
      const allCarsData = carsRes.data.data || carsRes.data;
      setAllCars(allCarsData);
      setCars(allCarsData.slice(0, 6));
      
      const brandsRes = await axios.get('http://localhost:5000/api/brands');
      setBrands(brandsRes.data.data || brandsRes.data);
      
      setLoading(false);
    } catch (error) {
      console.error('Lỗi tải dữ liệu:', error);
      setLoading(false);
    }
  };

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!searchKeyword.trim()) {
      setSearchResults(null);
      setSelectedBrand(null);
      setCars(allCars.slice(0, 6));
      return;
    }

    try {
      const res = await axios.get(`http://localhost:5000/api/cars/search?keyword=${searchKeyword}`);
      setSearchResults(res.data.data || res.data);
      setSelectedBrand(null);
    } catch (error) {
      console.error('Lỗi tìm kiếm:', error);
    }
  };

  const filterByBrand = (brand) => {
    console.log('Đang lọc theo hãng:', brand);
    setSelectedBrand(brand);
    setSearchKeyword('');
    setSearchResults(null);
  };

  const showAllCars = () => {
    console.log('Hiển thị tất cả xe');
    setSelectedBrand(null);
    setSearchResults(null);
    setCars(allCars.slice(0, 6));
  };

  const viewCarDetail = async (id) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/cars/${id}`);
      setSelectedCar(res.data.data || res.data);
    } catch (error) {
      console.error('Lỗi tải chi tiết xe:', error);
    }
  };

  const closeDetail = () => {
    setSelectedCar(null);
  };

  const handleBookTestDrive = (carId) => {
    if (!user) {
      alert('Vui lòng đăng nhập để đặt lịch lái thử');
      return;
    }
    navigate(`/test-drive/${carId}`);
  };

  const addToCart = async (carId) => {
    if (!user) {
      alert('Vui lòng đăng nhập để mua xe');
      return;
    }
    try {
      await axios.post('http://localhost:5000/api/cart', { car_id: carId });
      alert('✅ Đã thêm vào giỏ hàng!');
    } catch (error) {
      alert('Lỗi: ' + (error.response?.data?.message || 'Thêm vào giỏ thất bại'));
    }
  };

  const formatPrice = (price) => {
    return price.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ' ₫';
  };

  const clearSearch = () => {
    setSearchResults(null);
    setSearchKeyword('');
    setSelectedBrand(null);
    setCars(allCars.slice(0, 6));
  };

  if (loading) {
    return <div className="loading">Đang tải dữ liệu...</div>;
  }

  const displayCars = searchResults || cars;

  return (
    <>
      {/* Hero Section */}
      <section id="home" className="hero">
        <div className="container">
          <div className="hero-content">
            <h1>Tìm Kiếm Xe Mơ Ước Của Bạn</h1>
            <p>Hơn 500+ mẫu xe cao cấp từ các thương hiệu hàng đầu</p>
            
            <form onSubmit={handleSearch} style={{ 
              marginTop: '30px',
              display: 'flex',
              maxWidth: '500px',
              margin: '30px auto 0'
            }}>
              <input
                type="text"
                value={searchKeyword}
                onChange={(e) => setSearchKeyword(e.target.value)}
                placeholder="Nhập tên xe hoặc hãng xe..."
                style={{
                  flex: 1,
                  padding: '15px',
                  border: 'none',
                  borderRadius: '5px 0 0 5px',
                  fontSize: '16px'
                }}
              />
              <button
                type="submit"
                style={{
                  padding: '15px 30px',
                  background: '#e74c3c',
                  color: 'white',
                  border: 'none',
                  borderRadius: '0 5px 5px 0',
                  cursor: 'pointer',
                  fontSize: '16px',
                  fontWeight: 'bold'
                }}
              >
                🔍 Tìm
              </button>
            </form>

            {(searchResults || selectedBrand) && (
              <button
                onClick={clearSearch}
                style={{
                  marginTop: '15px',
                  padding: '10px 20px',
                  background: 'rgba(255,255,255,0.2)',
                  color: 'white',
                  border: '1px solid white',
                  borderRadius: '5px',
                  cursor: 'pointer'
                }}
              >
                ← Xem tất cả xe
              </button>
            )}
          </div>
        </div>
      </section>

      {/* Featured Cars / Search Results */}
<section id="cars" className="featured-cars">
  <div className="container">
    <h2 className="section-title">
      {searchResults 
        ? `Kết quả tìm kiếm (${displayCars.length})`
        : selectedBrand 
          ? `${selectedBrand} (${displayCars.length})`
          : '🔥 Xe Nổi Bật'
      }
    </h2>
    
    {displayCars.length === 0 ? (
      <div style={{ textAlign: 'center', padding: '50px' }}>
        <p style={{ fontSize: '18px', color: '#666' }}>
          Không tìm thấy xe phù hợp
        </p>
      </div>
    ) : (
      <div className="car-grid">
        {displayCars.map(car => (
          <div key={car.id} className="car-card">
            <div className="car-image">
              <img 
                src={car.image_url || 'https://via.placeholder.com/300x200'} 
                alt={car.name}
                onError={(e) => {
                  e.target.src = 'https://via.placeholder.com/300x200';
                }}
              />
              {/* Badge nổi bật cho xe hot */}
              {car.year >= 2023 && (
                <span className="car-badge">🔥 HOT 2024</span>
              )}
            </div>
            <div className="car-info">
              <h3>{car.name}</h3>
              <span className="car-brand">{car.brand}</span>
              <p className="price">
                {formatPrice(car.price)}
                <small> (đã bao gồm VAT)</small>
              </p>
              <div className="specs">
                <span>📅 {car.year}</span>
                <span>⛽ {car.fuel_type}</span>
                <span>⚡ {car.speed} km/h</span>
              </div>
              <div className="car-actions">
                <div className="car-actions-row">
                  <button 
                    onClick={() => viewCarDetail(car.id)} 
                    className="btn-detail"
                  >
                    📖 Xem Chi Tiết
                  </button>
                  <button 
                    onClick={() => addToCart(car.id)}
                    className="btn-buy"
                  >
                    🛒 Mua ngay
                  </button>
                </div>
                <button 
                  onClick={() => handleBookTestDrive(car.id)}
                  className="btn-test-drive"
                >
                  🚗 Đặt lịch lái thử
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    )}
  </div>
</section>

     {/* Brands - Có thể click để lọc */}
{!searchResults && (
  <section id="brands" className="brands">
    {/* ... phần brands giữ nguyên ... */}
  </section>
)}

{/* ========== PHẦN ĐỀ XUẤT XE NỔI TIẾNG ========== */}
{!searchResults && !selectedBrand && (
  <section className="featured-cars" style={{ background: '#fff', paddingTop: '0' }}>
    <div className="container">
      <h2 className="section-title">✨ Xe Đề Xuất</h2>
      <p style={{ textAlign: 'center', color: '#666', marginBottom: '40px' }}>
        Những mẫu xe được yêu thích nhất từ các thương hiệu hàng đầu thế giới
      </p>
      <div className="car-grid">
        {/* Lấy 1 xe từ mỗi thương hiệu nổi bật */}
        {['Ferrari', 'Lamborghini', 'Porsche', 'BMW', 'Mercedes', 'Audi', 'Tesla'].map(brand => {
          // Tìm xe của thương hiệu này
          const brandCar = allCars.find(car => car.brand === brand);
          if (!brandCar) return null;
          
          return (
            <div key={brandCar.id} className="car-card">
              <div className="car-image">
                <img 
                  src={brandCar.image_url || 'https://via.placeholder.com/300x200'} 
                  alt={brandCar.name}
                  onError={(e) => {
                    e.target.src = 'https://via.placeholder.com/300x200';
                  }}
                />
                <span className="car-badge" style={{
                  background: 'linear-gradient(135deg, #f39c12, #e67e22)'
                }}>
                  ⭐ Đề xuất
                </span>
              </div>
              <div className="car-info">
                <h3>{brandCar.name}</h3>
                <span className="car-brand">{brandCar.brand}</span>
                <p className="price">{formatPrice(brandCar.price)}</p>
                <div className="specs">
                  <span>📅 {brandCar.year}</span>
                  <span>⛽ {brandCar.fuel_type}</span>
                  <span>⚡ {brandCar.speed} km/h</span>
                </div>
                <div className="car-actions">
                  <div className="car-actions-row">
                    <button onClick={() => viewCarDetail(brandCar.id)} className="btn-detail">
                      📖 Xem Chi Tiết
                    </button>
                    <button onClick={() => addToCart(brandCar.id)} className="btn-buy">
                      🛒 Mua ngay
                    </button>
                  </div>
                  <button onClick={() => handleBookTestDrive(brandCar.id)} className="btn-test-drive">
                    🚗 Đặt lịch lái thử
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  </section>
)}

      {/* Car Detail Modal */}
      {selectedCar && (
        <div className="modal" onClick={closeDetail}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <span className="close" onClick={closeDetail}>&times;</span>
            
            <h2 style={{ marginBottom: '15px' }}>{selectedCar.name}</h2>
            
            <img 
              src={selectedCar.image_url || 'https://via.placeholder.com/500x300'} 
              alt={selectedCar.name}
              style={{ 
                width: '100%', 
                height: '250px', 
                objectFit: 'cover',
                borderRadius: '8px',
                marginBottom: '15px'
              }}
            />
            
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: '1fr 1fr', 
              gap: '10px',
              marginBottom: '15px'
            }}>
              <div style={{ background: '#f8f9fa', padding: '10px', borderRadius: '5px' }}>
                <div style={{ fontSize: '12px', color: '#666' }}>Giá</div>
                <div style={{ fontWeight: 'bold', color: '#e74c3c' }}>
                  {formatPrice(selectedCar.price)}
                </div>
              </div>
              <div style={{ background: '#f8f9fa', padding: '10px', borderRadius: '5px' }}>
                <div style={{ fontSize: '12px', color: '#666' }}>Hãng</div>
                <div style={{ fontWeight: 'bold' }}>{selectedCar.brand}</div>
              </div>
              <div style={{ background: '#f8f9fa', padding: '10px', borderRadius: '5px' }}>
                <div style={{ fontSize: '12px', color: '#666' }}>Năm SX</div>
                <div style={{ fontWeight: 'bold' }}>{selectedCar.year}</div>
              </div>
              <div style={{ background: '#f8f9fa', padding: '10px', borderRadius: '5px' }}>
                <div style={{ fontSize: '12px', color: '#666' }}>Nhiên liệu</div>
                <div style={{ fontWeight: 'bold' }}>{selectedCar.fuel_type}</div>
              </div>
              <div style={{ background: '#f8f9fa', padding: '10px', borderRadius: '5px' }}>
                <div style={{ fontSize: '12px', color: '#666' }}>Tốc độ</div>
                <div style={{ fontWeight: 'bold' }}>{selectedCar.speed} km/h</div>
              </div>
            </div>
            
            <p style={{ lineHeight: '1.6', color: '#666', marginBottom: '20px' }}>
              {selectedCar.description}
            </p>

            <div style={{ display: 'flex', gap: '10px', flexDirection: 'column' }}>
              <div style={{ display: 'flex', gap: '10px' }}>
                <button 
                  onClick={() => {
                    closeDetail();
                    navigate(`/car/${selectedCar.id}`);
                  }}
                  className="btn-detail"
                  style={{ flex: 1 }}
                >
                  Xem trang chi tiết
                </button>
                <button 
                  onClick={() => {
                    closeDetail();
                    addToCart(selectedCar.id);
                  }}
                  style={{
                    flex: 1,
                    background: '#3498db',
                    color: 'white',
                    border: 'none',
                    borderRadius: '5px',
                    padding: '12px',
                    cursor: 'pointer',
                    fontWeight: '500'
                  }}
                >
                  🛒 Mua ngay
                </button>
              </div>
              <button 
                onClick={() => {
                  closeDetail();
                  handleBookTestDrive(selectedCar.id);
                }}
                style={{
                  width: '100%',
                  background: '#27ae60',
                  color: 'white',
                  border: 'none',
                  borderRadius: '5px',
                  padding: '12px',
                  cursor: 'pointer',
                  fontWeight: '500'
                }}
              >
                📅 Đặt lịch lái thử
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default HomePage;
